"use client";
import { useEffect, useState } from "react";
import VendorSidebar from "../sidebar";
import { Booking, getVendorBookings, updateVendorBooking } from "../../../../lib/bookings";
import { formatINR } from "../../../../lib/vendors";

const label: Record<Booking["status"], string> = { pending: "Pending", confirmed: "Accepted", rejected: "Rejected", cancelled: "Cancelled", completed: "Completed" };
const badge: Record<Booking["status"], string> = { pending:"bg-amber-50 text-amber-800", confirmed:"bg-blue-50 text-blue-800", rejected:"bg-red-50 text-red-800", cancelled:"bg-slate-100 text-slate-700", completed:"bg-emerald-50 text-emerald-800" };
export default function VendorBookings() {
 const [bookings,setBookings]=useState<Booking[]>([]); const [error,setError]=useState(""); const [notice,setNotice]=useState(""); const [loading,setLoading]=useState(true); const [working,setWorking]=useState<number|null>(null);
 const load=()=>{setLoading(true);getVendorBookings().then(d=>{setBookings(d.bookings);setError("");}).catch(e=>setError(e.message||"Unable to load bookings.")).finally(()=>setLoading(false));}; useEffect(load,[]);
 async function transition(booking: Booking, action:"accept"|"reject"|"complete") { const verb=action === "accept" ? "accept" : action === "reject" ? "reject" : "mark completed"; if(!window.confirm(`Are you sure you want to ${verb} booking #${booking.id}?`)) return; setWorking(booking.id);setError("");try {const data=await updateVendorBooking(booking.id,action);setBookings(current=>current.map(item=>item.id===booking.id?data.booking:item));setNotice(`Booking #${booking.id} updated to ${label[data.booking.status]}.`);}catch(e:any){setError(e.message||"Unable to update booking.");}finally{setWorking(null);}}
 return <div className="min-h-screen bg-[#fffdfc] md:flex"><VendorSidebar/><main className="flex-1 p-5 pt-20 md:p-10"><p className="text-sm font-bold uppercase tracking-[.16em] text-[#8B000F]">Vendor workspace</p><h1 className="mt-2 font-serif text-4xl font-bold text-[#5c1632]">Booking requests</h1><p className="mt-2 text-slate-600">Accept, reject, or complete requests assigned to your business.</p>{notice&&<p role="status" className="mt-5 rounded-xl bg-emerald-50 p-4 text-emerald-800">{notice}</p>}{error&&<div role="alert" className="mt-5 rounded-xl bg-red-50 p-4 text-red-800">{error}<button onClick={load} className="ml-3 font-semibold underline">Retry</button></div>}<div className="mt-7 grid gap-4">{loading?Array.from({length:3}).map((_,i)=><div key={i} className="h-48 animate-pulse rounded-2xl bg-slate-100"/>):bookings.map(b=><article key={b.id} className="rounded-2xl border border-[#f0ded8] bg-white p-5 shadow-sm"><div className="flex flex-col justify-between gap-4 sm:flex-row"><div><p className="text-sm font-bold text-[#8B000F]">Request #{b.id}</p><h2 className="mt-1 text-lg font-bold text-[#6b1839]">{b.customer?.name || "Customer"}</h2><p className="mt-1 text-slate-700">{b.service.name} · {b.eventDate}</p><p className="text-sm text-slate-600">Venue: {b.eventLocation} · Requested {new Date(b.createdAt).toLocaleDateString("en-IN")}</p></div><span className={`h-fit w-fit rounded-full px-3 py-1 text-sm font-semibold ${badge[b.status]}`}>{label[b.status]}</span></div><p className="mt-4 font-semibold">Quoted from {formatINR(b.quotedPriceMinor)}</p>{b.customerMessage&&<p className="mt-3 rounded-xl bg-[#fff7f3] p-3 text-sm text-slate-700"><strong>Customer note:</strong> {b.customerMessage}</p>}{b.vendorResponse&&<p className="mt-3 rounded-xl bg-blue-50 p-3 text-sm text-blue-900"><strong>Your response:</strong> {b.vendorResponse}</p>}<div className="mt-5 flex flex-wrap gap-2">{b.status==="pending"&&<><button disabled={working===b.id} onClick={()=>transition(b,"accept")} className="rounded-lg bg-emerald-700 px-4 py-2 text-sm font-semibold text-white disabled:opacity-60">Accept</button><button disabled={working===b.id} onClick={()=>transition(b,"reject")} className="rounded-lg bg-red-700 px-4 py-2 text-sm font-semibold text-white disabled:opacity-60">Reject</button></>}{b.status==="confirmed"&&<button disabled={working===b.id} onClick={()=>transition(b,"complete")} className="rounded-lg bg-[#8B000F] px-4 py-2 text-sm font-semibold text-white disabled:opacity-60">Mark completed</button>}</div></article>)}{!loading&&!bookings.length&&<div className="rounded-2xl border border-dashed border-[#d9bcb1] bg-white p-10 text-center"><h2 className="font-bold text-[#6b1839]">No booking requests yet</h2><p className="mt-2 text-sm text-slate-600">New customer requests will appear here.</p></div>}</div></main></div>;
}
